1836   OverflowingBinaryOperator *Op1 = dyn_cast<OverflowingBinaryOperator>(RHS);
1837 
1838   if (!Op0 || !Op1)
1839     return nullptr;
1840 
1841   if (Op0->getOpcode() != Op1->getOpcode())
1842     return nullptr;
1843 
1844   if (!Op0->hasOneUse() || !Op1->hasOneUse())
1845     return nullptr;
1846 
1847   Instruction::BinaryOps InnerOpcode =
1848       static_cast<Instruction::BinaryOps>(Op0->getOpcode());
1849   bool HasNUW = Op0->hasNoUnsignedWrap() && Op1->hasNoUnsignedWrap();
1850   bool HasNSW = Op0->hasNoSignedWrap() && Op1->hasNoSignedWrap();
1851 
1852   Value *A = Op0->getOperand(0);
1853   Value *B = Op0->getOperand(1);
1854   Value *C = Op1->getOperand(0);
1855   Value *D = Op1->getOperand(1);
1856 
1857   // Attempts to swap variables such that A equals C or B equals D,
1858   // if the inner operation is commutative.
1859   if (Op0->isCommutative() && A != C && B != D) {
1860     if (A == D || B == C)
1861       std::swap(C, D);
1862     else
1863       return nullptr;
1864   }
