1866   BinaryOperator *NewBinop;
1867   if (A == C &&
1868       leftDistributesOverRight(InnerOpcode, HasNUW, HasNSW, TopLevelOpcode)) {
1869     Value *NewIntrinsic = Builder.CreateBinaryIntrinsic(TopLevelOpcode, B, D);
1870     NewBinop =
1871         cast<BinaryOperator>(Builder.CreateBinOp(InnerOpcode, A, NewIntrinsic));
1872   } else if (B == D && rightDistributesOverLeft(InnerOpcode, HasNUW, HasNSW,
1873                                                 TopLevelOpcode)) {
1874     Value *NewIntrinsic = Builder.CreateBinaryIntrinsic(TopLevelOpcode, A, C);
