2333     //
2334     // Examples:
2335     // max ~A, ~Y --> ~(min A, Y)
2336     // max ~A, C --> ~(min A, ~C)
2337     // max ~A, (max ~Y, ~Z) --> ~min( A, (min Y, Z))
2338     auto moveNotAfterMinMax = [&](Value *X, Value *Y) -> Instruction * {
2339       Value *A;
2340       if (match(X, m_OneUse(m_Not(m_Value(A)))) &&
2341           !isFreeToInvert(A, A->hasOneUse())) {
2342         if (Value *NotY = getFreelyInverted(Y, Y->hasOneUse(), &Builder)) {
2343           Intrinsic::ID InvID = getInverseMinMaxIntrinsic(IID);
2344           Value *InvMaxMin = Builder.CreateBinaryIntrinsic(InvID, A, NotY);
2345           return BinaryOperator::CreateNot(InvMaxMin);
2346         }
2347       }
2348       return nullptr;
2349     };
